def _compact_js(text: str) -> str:
    return re.sub(r"\s+", "", text).replace("'", '"')


def _dist_contract_result(checks: list[tuple[str, bool]], *, bundle: str = "") -> dict[str, Any]:
    results = [{"name": name, "ok": bool(ok), "detail": {}} for name, ok in checks]
    contract = {
        "checks": results,
        "ok": all(item["ok"] for item in results),
        "failed": [item["name"] for item in results if not item["ok"]],
    }
    if bundle:
        contract["bundle"] = bundle
    return contract


def applied_contract_checks(contract: dict[str, Any]) -> list[dict[str, Any]]:
    checks: list[dict[str, Any]] = []
    for check in contract.get("checks") or []:
        if not isinstance(check, dict):
            continue
        checks.append({
            "name": str(check.get("name") or ""),
            "ok": bool(check.get("ok")),
            "detail": dict(check.get("detail") or {}),
        })
    return checks


def require_deployed_contract(case: Any, contract_id: str, artifact_key: str) -> dict[str, Any]:
    contract = case.ctx.action.source_contract.deployed_contract_remote(contract_id)
    for check in applied_contract_checks(contract):
        case.require(check["name"], check["ok"], check["detail"])
    case.artifacts[artifact_key] = contract
    return contract


def task_treeview_projection_dist_contract(dist: str, *, bundle: str = "") -> dict[str, Any]:
    compact = _compact_js(dist)
    task_match = re.search(r"case\s*['\"]task['\"]", dist)
    task_start = task_match.start() if task_match else -1
    intern_group_match = re.search(r"case\s*['\"]intern-group['\"]", dist[task_start:] if task_start >= 0 else "")
    intern_group_start = task_start + intern_group_match.start() if task_start >= 0 and intern_group_match else -1
    task_block = dist[task_start:intern_group_start] if task_start >= 0 and intern_group_start > task_start else dist
    task_compact = _compact_js(task_block)
    open_readme_start = dist.find("tree.openTaskReadme")
    if open_readme_start >= 0:
        group_block = dist[max(0, open_readme_start - 1500):open_readme_start + 1500]
    else:
        group_match = re.search(r"['\"]task-group['\"]\s*===|===\s*['\"]task-group['\"]|taskGroupItems\.map|taskGroupItems", dist)
        group_start = group_match.start() if group_match else -1
        group_block = dist[group_start:group_start + 2500] if group_start >= 0 else dist
    readme_open_contract = (
        "existsSync" in dist
        and "vscode.open" in dist
        and "readmePath" in dist
        and "tree.openTaskReadme" in dist
    )
    readme_path_contract = "readmePath" in dist and "README.md" in dist and "metadataRootForProject" in dist
    group_compact = _compact_js(group_block)
    optional_task_command = (
        "vscode.open" in group_block
        and ("undefined" in group_block or "void 0" in group_block or "void0" in group_compact)
    ) or (readme_open_contract and "void0" in compact)
    inprogress_pr_guard = bool(re.search(
        r"(?:['\"]InProgress['\"]===[A-Za-z_$][\w$]*\.status|[A-Za-z_$][\w$]*\.status===['\"]InProgress['\"])&&[A-Za-z_$][\w$]*\.pr",
        task_compact,
    ))
    return _dist_contract_result([
        ("f0023_bundle_has_task_tree_item", "taskInfo" in dist and "tree.task.tooltip" in dist),
        ("f0023_inprogress_description_formats_pr", "PR#" in task_block and "InProgress" in task_block and "merge_requests" in task_block),
        ("f0023_tooltip_keeps_raw_pr", "tree.task.tooltip" in task_block and "PR:" in task_block),
        ("f0023_readme_open_requires_existing_file", readme_open_contract),
        ("f0023_readme_open_uses_task_readme_path", readme_path_contract),
        ("f0023_task_groups_use_expected_statuses", "InProgress" in dist and "Open" in dist and "Completed" in dist),
        ("f0023_task_node_command_is_optional", optional_task_command),
        ("f0023_non_inprogress_tasks_do_not_format_pr", "InProgress" in task_block and "PR#" in task_block and inprogress_pr_guard),
    ], bundle=bundle)


