def _dist_command_block(dist: str, command: str, *, window: int = 5000) -> str:
    start = dist.find(command)
    if start < 0:
        return ""
    next_match = re.search(r"registerCommand\(\s*['\"]intern\.", dist[start + len(command):])
    if next_match:
        end = start + len(command) + next_match.start()
        return dist[start:end]
    return dist[start:start + window]


def claude_treeview_command_dist_contract(
    dist: str,
    claude_rows: list[dict[str, str]],
    *,
    bundle: str = "",
    package_path: str = "",
) -> dict[str, Any]:
    compact = _compact_js(dist)
    claude_visible = [row["command"] for row in claude_rows]
    create_block = _dist_command_block(dist, "intern.createClaudeSession")
    restart_block = _dist_command_block(dist, "intern.restartClaudeSession")
    start_block = _dist_command_block(dist, "startCliTmuxSession", window=6500)
    restart_cli_block = _dist_command_block(dist, "sessionRestartCommand", window=4500) + _dist_command_block(dist, "runSessionRestart", window=4500)
    ensure_claude_block = _dist_command_block(dist, "ensureClaudeTmuxTerminal", window=6500)
    create_compact = _compact_js(create_block + ensure_claude_block + start_block)
    restart_compact = _compact_js(restart_block + restart_cli_block)
    required_menu = {
        "intern.openChatForIntern",
        "intern.createClaudeSession",
        "intern.restartClaudeSession",
        "intern.deleteIntern",
        "intern.forceDeleteIntern",
        "intern.setTriggerModeAll",
        "intern.setTriggerModeAtOnly",
        "intern.setDetailModeFull",
        "intern.setDetailModeSummary",
    }
    menu_missing = sorted(required_menu - set(claude_visible))
    codex_env_markers = [
        marker for marker in ("CODEX_RESUME_ON_START", "--resume-last", "resumeLast")
        if marker in (create_block + ensure_claude_block + start_block + restart_cli_block)
    ]
    contract = _dist_contract_result([
        ("f0044_bundle_has_claude_context_value", "intern-claude" in dist and "team-coordinator-claude" in dist),
        ("f0044_bundle_has_claude_terminal_icon", "terminal" in dist and "claude" in dist.lower()),
        ("f0044_package_menu_has_claude_commands", not menu_missing),
        ("f0044_create_claude_registered", 'registerCommand("intern.createClaudeSession"' in compact),
        ("f0044_create_claude_uses_session_start", '"session","start"' in create_compact and '"--type"' in create_compact and '"claude"' in create_compact and '"--no-attach"' in create_compact),
        ("f0044_restart_claude_registered", 'registerCommand("intern.restartClaudeSession"' in compact),
        ("f0044_restart_claude_uses_session_restart", '"session","restart"' in restart_compact and '"--type"' in restart_compact and '"claude"' in restart_compact and '"--no-attach"' in restart_compact),
        ("f0044_claude_command_has_no_codex_env_or_resume", not codex_env_markers),
        ("f0044_claude_menu_not_team_only", "intern-claude" in " ".join(row["when"] for row in claude_rows)),
    ], bundle=bundle)
    contract.update({
        "package": package_path,
        "claude_menu_rows": claude_rows,
        "claude_visible_commands": claude_visible,
        "menu_missing": menu_missing,
        "codex_env_markers": codex_env_markers,
        "create_block_tail": _compact_js(create_block + ensure_claude_block + start_block)[:1200],
        "restart_block_tail": _compact_js(restart_block + restart_cli_block)[:1200],
        "team_context_rows": [row for row in claude_rows if "team-coordinator-claude" in row["when"]],
    })
    return contract


def claude_skill_group_source_contract(
    dist: str,
    *,
    skill_text: str,
    skill_cli_source: dict[str, Any],
    claude_group_rows: list[dict[str, str]],
    skill_disabled: list[dict[str, str]],
    skill_repo: list[dict[str, str]],
    skill_personal: list[dict[str, str]],
    bundle: str = "",
) -> dict[str, Any]:
    compact = _compact_js(dist)
    required_group = {
        "intern.setTriggerModeAll",
        "intern.setTriggerModeAtOnly",
        "intern.setDetailModeFull",
        "intern.setDetailModeSummary",
    }
    visible_group = {row["command"] for row in claude_group_rows}
    contract = _dist_contract_result([
        ("f0045_cli_skill_declares_claude_farm", ".claude/skills" in skill_text and "CLAUDE_FARM_REL" in skill_text),
        ("f0045_cli_skill_preserves_codex_farm", ".agents/skills" in skill_text and "CODEX_FARM_REL" in skill_text),
        ("f0045_cli_skill_type_drives_farm", "farm_rel_for_type" in skill_text and "get_intern_type" in skill_text and "skill_sync" in skill_text),
        ("f0045_bundle_skill_tree_commands_registered", all(marker in compact for marker in (
            'registerCommand("intern.skill.tree.enableRepo"',
            'registerCommand("intern.skill.tree.enablePersonal"',
            'registerCommand("intern.skill.tree.disableRepo"',
            'registerCommand("intern.skill.tree.disablePersonal"',
        ))),
        ("f0045_package_skill_menus_visible", bool(skill_disabled and skill_repo and skill_personal)),
        ("f0045_claude_group_menu_commands_visible", required_group.issubset(visible_group)),
        ("f0045_group_commands_are_project_scoped_source", "runGroupModeCli" in dist and "--project" in dist and "pickInternFromContext" in dist),
    ], bundle=bundle)
    contract.update({
        "skill_cli_source": skill_cli_source,
        "claude_group_rows": claude_group_rows,
        "skill_rows": {
            "disabled": skill_disabled,
            "repo": skill_repo,
            "personal": skill_personal,
        },
        "group_visible_commands": sorted(visible_group),
        "group_missing": sorted(required_group - visible_group),
    })
    return contract
